<?php
 namespace WPAICG\Core\Providers\Azure\Methods; use WPAICG\Core\Providers\AzureProviderStrategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function get_models_logic(AzureProviderStrategy $strategyInstance, array $api_params): array|WP_Error { $url = $strategyInstance->build_api_url('deployments', $api_params); if (is_wp_error($url)) { return $url; } $headers = $strategyInstance->get_api_headers($api_params['api_key'], 'deployments'); $options = $strategyInstance->get_request_options('models'); $options['method'] = 'GET'; $response = wp_remote_get($url, array_merge($options, ['headers' => $headers])); if (is_wp_error($response)) { return $response; } $status_code = wp_remote_retrieve_response_code($response); $body = wp_remote_retrieve_body($response); if ($status_code !== 200) { $error_msg = $strategyInstance->parse_error_response($body, $status_code); return new WP_Error('api_error_azure_deployments_logic', sprintf('Azure API Error (HTTP %d): %s', $status_code, esc_html($error_msg))); } $decoded = $strategyInstance->decode_json_public($body, 'Azure Deployments'); if (is_wp_error($decoded)) { return $decoded; } $raw_deployments = $decoded['data'] ?? []; $formatted = []; foreach ($raw_deployments as $dep) { $dep_id = $dep['id'] ?? null; $model_name = $dep['model'] ?? null; $status = $dep['status'] ?? ''; if (!empty($dep_id) && $status === 'succeeded') { $display_name = $dep_id; if ($model_name && $model_name !== $dep_id) { $display_name .= " ({$model_name})"; } $formatted[] = [ 'id' => $dep_id, 'name' => $display_name, 'status' => $status, 'model' => $model_name ]; } } usort($formatted, fn($a, $b) => strcmp($a['id'] ?? '', $b['id'] ?? '')); return $formatted; }